# MUD Server — Step 7: NPC System
import re
import socket
import threading
from collections import deque


class PlayerConnection:
    """Represents a single player's TCP connection."""

    def __init__(self, sock, address, player_name='Unknown'):
        self.socket = sock
        self.address = address
        self.player_name = player_name

    def send(self, message):
        try:
            self.socket.sendall(message.encode('utf-8'))
        except OSError:
            pass


class MUDServer:
    """A TCP server for the Multi-User Dungeon."""

    def __init__(self, host='127.0.0.1', port=7777):
        self.host = host
        self.port = port
        self._running = False
        self._socket = None
        self.connections = []

    @property
    def is_running(self):
        return self._running

    def start(self):
        self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self._socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self._socket.bind((self.host, self.port))
        self._socket.listen(5)
        self._running = True

    def stop(self):
        self._running = False
        for conn in self.connections:
            try:
                conn.socket.close()
            except OSError:
                pass
        self.connections.clear()
        if self._socket:
            try:
                self._socket.close()
            except OSError:
                pass
            self._socket = None

    def add_connection(self, player_conn):
        self.connections.append(player_conn)

    def remove_connection(self, player_conn):
        if player_conn in self.connections:
            self.connections.remove(player_conn)

    def broadcast(self, message):
        for conn in list(self.connections):
            try:
                conn.send(message)
            except OSError:
                pass


class ConnectionManager:
    """Thread-safe manager for player connections."""

    def __init__(self):
        self._players = {}
        self._lock = threading.Lock()

    def add_player(self, connection):
        with self._lock:
            self._players[connection.player_name] = connection

    def remove_player(self, name):
        with self._lock:
            self._players.pop(name, None)

    def get_player(self, name):
        with self._lock:
            return self._players.get(name)

    def get_all_players(self):
        with self._lock:
            return list(self._players.values())

    @property
    def player_count(self):
        with self._lock:
            return len(self._players)


class Room:
    """A single room in the MUD world."""

    def __init__(self, name, description, exits=None, items=None, npcs=None):
        self.name = name
        self.description = description
        self.exits = exits or {}
        self.items = items or []
        self.npcs = npcs or []
        self.players_here = set()

    def add_player(self, player_name):
        self.players_here.add(player_name)

    def remove_player(self, player_name):
        self.players_here.discard(player_name)

    def get_exit(self, direction):
        return self.exits.get(direction)


class Zone:
    """A collection of related rooms."""

    def __init__(self, name):
        self.name = name
        self.rooms = {}

    def add_room(self, room):
        self.rooms[room.name] = room

    def get_room(self, room_name):
        return self.rooms.get(room_name)


class World:
    """The entire MUD world, composed of zones and rooms."""

    def __init__(self):
        self._zones = {}
        self._rooms = {}

    def add_zone(self, zone):
        self._zones[zone.name] = zone
        for room_name, room in zone.rooms.items():
            self._rooms[room_name] = room

    def get_room(self, room_name):
        return self._rooms.get(room_name)

    def move_player(self, player_name, direction, current_room_name):
        current_room = self.get_room(current_room_name)
        if current_room is None:
            return None
        dest_name = current_room.get_exit(direction)
        if dest_name is None:
            return None
        dest_room = self.get_room(dest_name)
        if dest_room is None:
            return None
        current_room.remove_player(player_name)
        dest_room.add_player(player_name)
        return dest_room

    @property
    def room_count(self):
        return len(self._rooms)


class MUDParser:
    """Parses player text input into MUD commands."""

    COMMANDS = {
        'look': r'^look$',
        'go': r'^go\s+(?P<direction>\w+)$',
        'say': r'^say\s+(?P<message>.+)$',
        'tell': r'^tell\s+(?P<player>\w+)\s+(?P<message>.+)$',
        'take': r'^take\s+(?P<item>.+)$',
        'drop': r'^drop\s+(?P<item>.+)$',
        'inventory': r'^inventory$',
        'who': r'^who$',
        'emote': r'^emote\s+(?P<action>.+)$',
        'attack': r'^attack\s+(?P<target>\w+)$',
        'help': r'^help$',
    }

    def __init__(self):
        self._patterns = [(name, re.compile(pat, re.IGNORECASE))
                          for name, pat in self.COMMANDS.items()]

    def parse(self, input_str):
        cleaned = input_str.strip()
        for cmd_name, pattern in self._patterns:
            match = pattern.match(cleaned)
            if match:
                return (cmd_name, match.groupdict())
        return ('unknown', {'input': input_str.strip()})


class ChatChannel:
    """A named chat channel with membership and message history."""

    def __init__(self, name):
        self.name = name
        self.members = set()
        self.history = deque(maxlen=100)

    def join(self, player_name):
        self.members.add(player_name)

    def leave(self, player_name):
        self.members.discard(player_name)

    def send(self, player_name, message):
        formatted = f'[{self.name}] {player_name}: {message}'
        self.history.append(formatted)

    def get_history(self, count=10):
        return list(self.history)[-count:]

    @property
    def member_count(self):
        return len(self.members)


class ChannelManager:
    """Manages chat channels for the MUD."""

    DEFAULT_CHANNELS = ['global', 'trade', 'help']

    def __init__(self):
        self._channels = {}
        for name in self.DEFAULT_CHANNELS:
            self.create_channel(name)

    def create_channel(self, name):
        channel = ChatChannel(name)
        self._channels[name] = channel
        return channel

    def get_channel(self, name):
        return self._channels.get(name)

    def list_channels(self):
        return sorted(self._channels.keys())


class Character:
    """A player character with stats and leveling."""

    def __init__(self, name, char_class, health, attack, defense):
        self.name = name
        self.char_class = char_class
        self.level = 1
        self.health = health
        self.max_health = health
        self.attack = attack
        self.defense = defense
        self.experience = 0
        self.gold = 0

    def gain_exp(self, amount):
        self.experience += amount
        while self.experience >= self.level * 100:
            self.level_up()

    def level_up(self):
        self.level += 1
        self.max_health += 10
        self.health = self.max_health
        self.attack += 2
        self.defense += 1

    def is_alive(self):
        return self.health > 0

    def take_damage(self, amount):
        self.health = max(0, self.health - amount)

    def heal(self, amount):
        self.health = min(self.max_health, self.health + amount)


class CharacterCreator:
    """Creates new characters with class-specific base stats."""

    CLASS_STATS = {
        'warrior': {'health': 120, 'attack': 15, 'defense': 12},
        'mage':    {'health': 80,  'attack': 20, 'defense': 8},
        'rogue':   {'health': 100, 'attack': 18, 'defense': 10},
    }

    def create(self, name, char_class):
        stats = self.CLASS_STATS.get(char_class)
        if stats is None:
            raise ValueError(f'Unknown character class: {char_class}')
        return Character(name, char_class, stats['health'], stats['attack'], stats['defense'])


